import type { Meta, StoryObj } from '@storybook/react';

import { Button } from '../components/Button';


const meta: Meta<typeof Button> = {
  component: Button,
  argTypes: {
    onclick
  }
};

export default meta;
type Story = StoryObj<typeof Button>;

export const Primary: Story = {
  args: {
    onclick: alert("click"),
    children: 'Click Me!',
    variant: 'secondary',
    label: 'Button'
  },
};
